# ── Mock Data Store ──────────────────────────────────────────────────────────

class MockDataStore:
    def __init__(self):
        self.collections = {} # path -> list[dict]
        self.static_responses = {} # "METHOD /path" -> data

    def load(self, endpoints, mock_data):
        for ep in endpoints:
            method = ep.get("method", "GET")
            path = ep.get("path", "")
            key = f"{method} {path}"
            data = mock_data.get(key)

            if method == "GET" and "{" not in path:
                if isinstance(data, dict):
                    items = data.get("members") or data.get("items") or []
                    self.collections[path] = list(items)
                else:
                    self.collections.setdefault(path, [])
                self.static_responses[key] = data
            else:
                self.static_responses[key] = data

    def get_collection(self, path, start=0, count=50, filter_str=None, sort=None):
        items = self.collections.get(path, [])
        if filter_str:
            items = [i for i in items if filter_str.lower() in json.dumps(i).lower()]
        if sort:
            field = sort.split(":")[0].strip()
            reverse = "desc" in sort.lower()
            items = sorted(items, key=lambda x: str(x.get(field, "")), reverse=reverse)
        
        page = items[start : start + count]
        template = self.static_responses.get(f"GET {path}", {}) or {}
        list_key = "members" if "members" in template else "items"
        return {**template, list_key: page, "count": len(page), "total": len(items), "start": start, "uri": path}

    def get_resource(self, collection_path, resource_id):
        for item in self.collections.get(collection_path, []):
            uri = item.get("uri", "")
            if uri.endswith(resource_id) or item.get("uuid") == resource_id or str(item.get("id")) == resource_id:
                return item
        return None

    def create_resource(self, collection_path, data):
        new_id = str(uuid.uuid4()).upper()
        data.setdefault("uri", f"{collection_path}/{new_id}")
        data.setdefault("uuid", new_id)
        now = datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")
        data.setdefault("created", now)
        data["modified"] = now
        self.collections.setdefault(collection_path, []).append(data)
        return data

    def update_resource(self, collection_path, resource_id, data):
        items = self.collections.get(collection_path, [])
        for i, item in enumerate(items):
            uri = item.get("uri", "")
            if uri.endswith(resource_id) or item.get("uuid") == resource_id or str(item.get("id")) == resource_id:
                now = datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")
                items[i] = {**item, **data, "modified": now}
                return items[i]
        return None

    def delete_resource(self, collection_path, resource_id):
        items = self.collections.get(collection_path, [])
        for i, item in enumerate(items):
            uri = item.get("uri", "")
            if uri.endswith(resource_id) or item.get("uuid") == resource_id or str(item.get("id")) == resource_id:
                return items.pop(i)
        return None

