# ── Routes ───────────────────────────────────────────────────────────────────

@app.get("/")
async def root():
    return {
        "title": API_SPEC.get("title"),
        "version": API_SPEC.get("version"),
        "endpoints_count": len(API_SPEC.get("endpoints", [])),
        "docs": "/docs"
    }

@app.api_route("/{path:path}", methods=["GET", "POST", "PUT", "PATCH", "DELETE"], include_in_schema=False)
async def catch_all(request: Request, path: str, start: int = 0, count: int = 50, filter: Optional[str] = None):
    full_path = request.url.path
    method = request.method
    
    # ── 1. Exact Match ───────────────────────────────────────────
    key = f"{method} {full_path}"
    if full_path in store.collections and method == "GET":
        return JSONResponse(store.get_collection(full_path, start, count, filter))
    
    if key in MOCK_DATA:
        if method == "POST":
            body = await request.json() if request.get("content-type") == "application/json" else {}
            return JSONResponse(store.create_resource(full_path, body), status_code=201)
        return JSONResponse(MOCK_DATA[key])

    # ── 2. Pattern Match ─────────────────────────────────────────
    for ep in API_SPEC.get("endpoints", []):
        if ep["method"] != method or "{" not in ep["path"]:
            continue
        
        # Simple regex conversion
        regex_pattern = re.sub(r"\{(\w+)\}", r"(?P<\1>[^/]+)", ep["path"])
        match = re.match(f"^{regex_pattern}$", full_path)
        if match:
            resource_id = match.groupdict().get("id", "")
            collection_path = re.sub(r"/\{[^}]+\}$", "", ep["path"])
            
            if method == "GET":
                res = store.get_resource(collection_path, resource_id)
                return JSONResponse(res) if res else JSONResponse({"error": "Not Found"}, status_code=404)
            elif method in ("PUT", "PATCH"):
                body = await request.json()
                res = store.update_resource(collection_path, resource_id, body)
                return JSONResponse(res) if res else JSONResponse({"error": "Not Found"}, status_code=404)
            elif method == "DELETE":
                res = store.delete_resource(collection_path, resource_id)
                return JSONResponse(None, status_code=204) if res else JSONResponse({"error": "Not Found"}, status_code=404)

    return JSONResponse({"error": "Not Found", "path": full_path}, status_code=404)

